#include <stdio.h>
#include <stdbool.h>

int main() {
  bool isHappy = true;
  bool isTired = false;
  int x = 10;
  printf("Happy: %d\n", isHappy);
  printf("Tired: %d\n", isTired);
  printf("x > 5: %d\n", x > 5);
  printf("x == 10: %d\n", x == 10);
  printf("!isTired: %d\n", !isTired);
  return 0;
}
